import React from "react";
import ReactDOM from "react-dom/client";
import { BrowserRouter } from "react-router-dom";
import SmoothScroll from "./lib/SmoothScroll.jsx";
import App from "./App.jsx";
import "./index.css";

// Root deploy on a custom domain (kartar.ai) → BrowserRouter basename="/".
// Clean URLs on GitHub Pages rely on the spa-github-pages 404.html redirect +
// the restore snippet in index.html (runs before this module).
// SmoothScroll (S03) mounts ONCE here — inside the Router (it reads location
// for the scroll-to-top reset + ?route/?jump flags), outside the per-route
// Outlet so the Lenis instance survives navigation (scar #2/#9).
ReactDOM.createRoot(document.getElementById("root")).render(
  <React.StrictMode>
    <BrowserRouter basename="/">
      <SmoothScroll>
        <App />
      </SmoothScroll>
    </BrowserRouter>
  </React.StrictMode>
);

import { Outlet } from "react-router-dom";
import StubNav from "./StubNav.jsx";
import StubFooter from "./StubFooter.jsx";
import Preloader from "../components/Preloader.jsx";

// Layout route: nav + routed Outlet + footer. The Outlet wrapper is a PLAIN
// block — NOT a transformed scroll container (scar #2). Lenis scrolls the real
// window. The page-transition seam (chapter-wipe overlay) is S05/S13's job and
// must remain an overlay, never wrap the Outlet in a transform.
// Preloader (S03) lives here — the layout route persists across navigations,
// so it mounts once per hard load; the sessionStorage gate keeps it to once
// per session.
export default function RootLayout() {
  return (
    <div className="relative min-h-screen bg-ground text-ink">
      <Preloader />
      <StubNav />
      <main id="main">
        <Outlet />
      </main>
      <StubFooter />
    </div>
  );
}

