import { NavLink } from "react-router-dom";
import { NAV } from "../data/nav.js";
import { LINKS } from "../data/links.js";

// MINIMAL nav stub — full chrome (magnetic CTA, scroll state, mobile menu,
// blueprint styling) is S05's job. This exists only so every route renders its
// own routed links + a Calendly CTA (one of the >=3 site-wide occurrences).
// SEAM: S05 replaces this component with the real Navbar.
export default function StubNav() {
  return (
    <nav className="sticky top-0 z-50 border-b border-line bg-ground/90 backdrop-blur">
      <div className="mx-auto flex max-w-[1280px] items-center justify-between gap-3 px-[clamp(1.25rem,4vw,3rem)] py-4">
        <NavLink to="/" className="shrink-0 font-display text-lg font-bold text-ink">
          kartar<span className="text-accent">AI</span>
        </NavLink>
        <div className="flex items-center gap-6">
          {/* Route links collapse below sm — the stacked footer nav keeps all 4
              routes reachable on mobile. The real mobile menu is S05's job. */}
          <div className="hidden items-center gap-6 sm:flex">
            {NAV.map((item) => (
              <NavLink
                key={item.to}
                to={item.to}
                end={item.to === "/"}
                className={({ isActive }) =>
                  `font-body text-sm transition-colors ${
                    isActive ? "text-ink" : "text-ink-dim hover:text-ink"
                  }`
                }
              >
                {item.label}
              </NavLink>
            ))}
          </div>
          <a
            href={LINKS.calendly}
            target="_blank"
            rel="noopener noreferrer"
            className="shrink-0 rounded-sm bg-accent px-4 py-2 font-body text-sm font-medium text-ground transition-colors hover:brightness-110"
          >
            Book a Call
          </a>
        </div>
      </div>
    </nav>
  );
}

import { Link } from "react-router-dom";
import { NAV } from "../data/nav.js";
import { LINKS } from "../data/links.js";
import { BRAND } from "../data/brand.js";

// MINIMAL footer stub — full chrome (blueprint title-block, real Sender render,
// styling) is S05/S14. This exists so the global #newsletter anchor + Sender
// mount, the company LinkedIn, mailto and a Calendly CTA resolve from EVERY
// route (the CTA banner relies on cross-route #newsletter; facts_check counts
// these site-wide). SEAM: S05 replaces this with the real Footer.
export default function StubFooter() {
  return (
    <footer className="border-t border-line bg-surface-2 text-ink-dim">
      <div className="mx-auto max-w-[1280px] px-[clamp(1.25rem,4vw,3rem)] py-16">
        <div className="grid gap-12 md:grid-cols-3">
          <div>
            <Link to="/" className="font-display text-lg font-bold text-ink">
              {BRAND.wordmark}
            </Link>
            <p className="mt-3 max-w-xs font-body text-sm text-ink-dim">
              {BRAND.name}. Agentic AI systems and AI-native products for Indian
              businesses.
            </p>
            <div className="mt-4 flex flex-col gap-2 text-sm">
              <a className="hover:text-ink" href={`mailto:${LINKS.email}`}>
                {LINKS.email}
              </a>
              <a
                className="hover:text-ink"
                href={LINKS.linkedinCompany}
                target="_blank"
                rel="noopener noreferrer"
              >
                LinkedIn
              </a>
              <a
                className="hover:text-ink"
                href={LINKS.calendly}
                target="_blank"
                rel="noopener noreferrer"
              >
                Book a call
              </a>
            </div>
          </div>

          <nav className="flex flex-col gap-2 text-sm" aria-label="Footer">
            {NAV.map((item) => (
              <Link key={item.to} to={item.to} className="hover:text-ink">
                {item.label}
              </Link>
            ))}
          </nav>

          {/* #newsletter — the one hard cross-route anchor the CTA banner targets.
              Sender injects the form async into this mount; the universal script
              lives in index.html. S14 finalizes the rendered form. */}
          <section id="newsletter" aria-labelledby="newsletter-title">
            <h2
              id="newsletter-title"
              className="font-mono text-[0.6875rem] uppercase tracking-[0.12em] text-muted"
            >
              Newsletter
            </h2>
            <p className="mt-2 font-body text-sm text-ink-dim">
              Get occasional notes on what we are building.
            </p>
            <div
              className="sender-form-field mt-4"
              data-sender-form-id={LINKS.sender.formId}
            />
          </section>
        </div>

        <p className="mt-12 border-t border-line pt-6 font-mono text-[0.6875rem] uppercase tracking-[0.12em] text-muted">
          © {new Date().getFullYear()} {BRAND.name}
        </p>
      </div>
    </footer>
  );
}

// Single-source external links + integration ids — byte-exact from facts.json
// (PROTOCOL §8 locked facts). Calendly URL lives here ONCE; every CTA consumes
// LINKS.calendly so the >=3 site-wide occurrences are the same constant.
export const LINKS = {
  calendly: "https://calendly.com/sachmeet-kartar/30min",
  email: "hello@kartar.ai",
  linkedinCompany: "https://www.linkedin.com/company/kartar-ai/",
