// Single-source nav links — consumed by Navbar + Footer (kills old duplication).
// Locked IA from plans/design/DIRECTION.md §IA.
export const NAV = [
  { to: "/", label: "Home" },
  { to: "/work", label: "Work" },
  { to: "/studio", label: "Studio" },
  { to: "/contact", label: "Contact" },
];

