/**
 * MagneticCursor — custom cursor companion (mount-once overlay).
 *
 * A fixed, pointer-events-none pair: an accent dot (~6px) that lerps tight to
 * the pointer and a ring (size px) that lags behind. ONE gsap.ticker callback
 * lerps cached pointer coords (dot ~0.35, ring ~0.16) into two quickSetters
 * (built once). On hovering any a/button/[data-cursor] the ring scales up and
 * the dot fades (two quickTos). This is purely ADDITIVE — the OS cursor is
 * never hidden.
 *
 * Props:
 *   size  number  32  ring diameter in px (the dot stays ~6px).
 *
 * Gate (scar #8 + coarse): useCoarsePointer() OR useMotionStatic() ⇒ return
 * null. On touch / reduced-motion / mobile there is no custom cursor at all
 * (the native cursor is untouched). Nothing rendered ⇒ no static frame needed.
 *
 * Reduced/mobile fallback: render nothing (return null).
 *
 * Scars: #1 n/a. #4 n/a (no absolute children; both nodes are position:fixed).
 * pointermove on window writes into module-local lets — zero per-frame
 * allocations; the single ticker callback creates no objects/closures per tick
 * and reads no getBoundingClientRect. All GSAP inside the component's own
 * gsap.context; cleanup removes ticker + listeners and reverts (StrictMode
 * idempotent). Hidden (opacity 0) until the first pointermove.
 */
import { useLayoutEffect, useRef } from "react";
import { gsap } from "gsap";
import { useCoarsePointer, useMotionStatic } from "./useMotionStatic.js";
import { EASE } from "../../lib/motion.js";

function MagneticCursor({ size = 32 }) {
  const coarse = useCoarsePointer();
  const isStatic = useMotionStatic();
  const dotRef = useRef(null);
  const ringRef = useRef(null);

  const off = coarse || isStatic;

  useLayoutEffect(() => {
    if (off) return undefined;
    const dot = dotRef.current;
    const ring = ringRef.current;
    if (!dot || !ring) return undefined;

    const ctx = gsap.context(() => {
      // Module-scope-equivalent state held in the closure of THIS effect run.
      // pointermove only mutates pointerX/pointerY — zero allocations per move.
      let pointerX = window.innerWidth / 2;
      let pointerY = window.innerHeight / 2;
      let dotX = pointerX;
      let dotY = pointerY;
      let ringX = pointerX;
      let ringY = pointerY;
      let visible = false;

      const setDot = gsap.quickSetter(dot, "x,y", "px");
      const setRing = gsap.quickSetter(ring, "x,y", "px");
      const ringScale = gsap.quickTo(ring, "scale", {
        duration: 0.3,
        ease: EASE.SETTLE,
      });
      const dotOpacity = gsap.quickTo(dot, "opacity", {
        duration: 0.3,
        ease: EASE.SETTLE,
      });

      const onPointerMove = (e) => {
        pointerX = e.clientX;
        pointerY = e.clientY;
        if (!visible) {
          visible = true;
          gsap.to([dot, ring], { autoAlpha: 1, duration: 0.3, ease: EASE.SETTLE });
        }
      };

      const onPointerOver = (e) => {
        const t = e.target;
        if (t && t.closest && t.closest("a, button, [data-cursor]")) {
          ringScale(1.6);
          dotOpacity(0);
        }
      };
      const onPointerOut = (e) => {
        const t = e.target;
        if (t && t.closest && t.closest("a, button, [data-cursor]")) {
          ringScale(1);
          dotOpacity(1);
        }
      };

      function tick() {
        dotX += (pointerX - dotX) * 0.35;
        dotY += (pointerY - dotY) * 0.35;
        ringX += (pointerX - ringX) * 0.16;
        ringY += (pointerY - ringY) * 0.16;
        setDot(dotX, dotY);
        setRing(ringX, ringY);
      }

      window.addEventListener("pointermove", onPointerMove);
      document.addEventListener("pointerover", onPointerOver);
      document.addEventListener("pointerout", onPointerOut);
      gsap.ticker.add(tick);

      return () => {
        gsap.ticker.remove(tick);
        window.removeEventListener("pointermove", onPointerMove);
        document.removeEventListener("pointerover", onPointerOver);
        document.removeEventListener("pointerout", onPointerOut);
      };
    });

    return () => ctx.revert();
  }, [off]);

  if (off) return null;

  return (
    <>
      <div
        ref={dotRef}
        aria-hidden="true"
        className="pointer-events-none fixed left-0 top-0 z-[90] rounded-full bg-accent opacity-0"
        style={{
          width: 6,
          height: 6,
          marginLeft: -3,
          marginTop: -3,
          visibility: "hidden",
        }}
      />
      <div
        ref={ringRef}
        data-magnetic-cursor
        aria-hidden="true"
        className="pointer-events-none fixed left-0 top-0 z-[90] rounded-full border border-line-2 opacity-0"
        style={{
          width: size,
          height: size,
          marginLeft: -size / 2,
          marginTop: -size / 2,
          visibility: "hidden",
        }}
      />
    </>
  );
}

export default MagneticCursor;
export { MagneticCursor };

