import React, {
  createContext,
  useContext,
  useEffect,
  useLayoutEffect,
  useRef,
  useState,
} from "react";
import { useLocation, useNavigate } from "react-router-dom";
import Lenis from "lenis";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { refreshSoon } from "./useRouteScrollContext";
import { prefersReducedMotion, isMobileViewport } from "./useReducedMotion";

gsap.registerPlugin(ScrollTrigger);

const LenisContext = createContext(null);

/** Access the live Lenis instance (null in native-scroll mode or early). */
export function useLenis() {
  return useContext(LenisContext);
}

/**
 * SmoothScroll v2 — the router-aware scroll engine.
 *
 * - Lenis scrolls the REAL window (no scrollerProxy, no wrapper — scar #2).
 * - Driven from the single gsap.ticker (never a bare rAF — motion law 5).
 * - Mounts ONCE at app root, inside the Router, outside the per-route Outlet:
 *   the instance SURVIVES route changes; navigation only resets scroll to top
 *   (`lenis.scrollTo(0, { immediate: true })`, scar #9).
 * - Reduced-motion or mobile (<=768): NO Lenis — plain native scroll, zero
 *   smoothing artifacts (tier matrix). ScrollTrigger tracks the window itself.
 * - Owns the ONE coordinated refresh (scar #3): document.fonts.ready +
 *   `preloaderDone` both funnel into the debounced refreshSoon().
 * - Dev/QA: exposes window.__lenis; honors ?route=<path> and ?jump=<px>.
 */
export default function SmoothScroll({ children }) {
  const [lenis, setLenis] = useState(null);
  const location = useLocation();
  const navigate = useNavigate();
  const firstRouteRef = useRef(true);

  // --- Lenis lifecycle (once; StrictMode-idempotent: create/destroy/create) --
  useEffect(() => {
    if (prefersReducedMotion() || isMobileViewport()) {
      // Native scroll tier. window.__lenis stays undefined — QA scripts fall
      // back to window.scrollTo on this path by design.
      return undefined;
    }

    const instance = new Lenis({
      duration: 1.1,
      easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
      smoothWheel: true,
      touchMultiplier: 1.5,
    });
    setLenis(instance);
    window.__lenis = instance;

    instance.on("scroll", ScrollTrigger.update);
    const tick = (time) => instance.raf(time * 1000);
    gsap.ticker.add(tick);
    gsap.ticker.lagSmoothing(0);

    return () => {
      gsap.ticker.remove(tick);
      instance.off("scroll", ScrollTrigger.update);
      instance.destroy();
      if (window.__lenis === instance) delete window.__lenis;
      setLenis(null);
    };
  }, []);

  // --- Coordinated initial refresh: fonts + preloader (scar #3) -------------
  useEffect(() => {
    let disposed = false;
    const ready = { fonts: false, preloader: !!window.__preloaderDone };
    const maybe = () => {
      if (!disposed && ready.fonts && ready.preloader) refreshSoon();
    };
    document.fonts.ready.then(() => {
      ready.fonts = true;
      maybe();
    });
    const onPreloaderDone = () => {
      ready.preloader = true;
      maybe();
    };
    window.addEventListener("preloaderDone", onPreloaderDone);
    return () => {
      disposed = true;
      window.removeEventListener("preloaderDone", onPreloaderDone);
    };
  }, []);

  // --- Route change: scroll to top, then one coordinated refresh (scar #9) --
  // Layout effect so the reset lands in the same commit the new route paints.
  // The OLD route's gsap.context has already reverted by now (its cleanup runs
  // before the new route's effects), so refresh measures only live triggers.
  useLayoutEffect(() => {
    if (firstRouteRef.current) {
      firstRouteRef.current = false;
      return;
    }
    if (window.__lenis) window.__lenis.scrollTo(0, { immediate: true });
    else window.scrollTo(0, 0);
    refreshSoon();
  }, [location.pathname]);

  // --- Dev/QA flags: ?route=<path> (deep-link helper), ?jump=<px> -----------
  useEffect(() => {
    const q = new URLSearchParams(window.location.search);

    const route = q.get("route");
    if (route && route.startsWith("/") && route !== window.location.pathname) {
      navigate(route, { replace: true });
    }

    const jump = parseInt(q.get("jump") || "", 10);
    if (Number.isFinite(jump) && jump > 0) {
      const go = () =>
        gsap.delayedCall(0.5, () => {
          if (window.__lenis) window.__lenis.scrollTo(jump, { immediate: true });
          else window.scrollTo(0, jump);
        });
      if (window.__preloaderDone) go();
      else window.addEventListener("preloaderDone", go, { once: true });
      return () => window.removeEventListener("preloaderDone", go);
    }
    return undefined;
    // run once on load — flags are read from the initial URL only
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <LenisContext.Provider value={lenis}>{children}</LenisContext.Provider>
  );
}

