473	  const labUrl = DEV_URL + "/lab?skippreload";
474	
475	  // (a) DESKTOP — motion tier: everything mounts, strikes fire, latches commit.
476	  {
477	    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
478	    const consoleErrors = [];
