622	        readout: document.querySelector("[data-lab-progress]")?.textContent.trim(),
623	        hasText: document.body.innerText.trim().length > 400,
624	      };
625	    }, LAB_BLOCKS);
626	    check("[lab] reduced: static fallbacks rendered (>= 11 blocks)", r.blocksWithStatic >= 11, `(${r.blocksWithStatic})`);
627	    check("[lab] reduced: zero pins", r.pinSpacers === 0, `(${r.pinSpacers})`);
628	    check("[lab] reduced: no custom cursor", !r.cursor);
629	    check("[lab] reduced: SplitLines static text fully readable", r.splitText);
630	    check("[lab] reduced: InkReveal final state visible", r.inkVisible);
631	    check(
632	      "[lab] reduced: CountStrike shows final numbers immediately",
633	      r.counts.some((t) => t.includes("2,41,800")) && r.counts.some((t) => t.includes("99.3")),
634	      `(${r.counts.join(" | ")})`
