637	    check("[lab] reduced: content present (not blank)", r.hasText);
638	    const leaked = requests.filter((u) => GL_CHUNKS.test(u));
639	    check("[lab] reduced: zero GL chunks fetched", leaked.length === 0, leaked[0] ? `leaked: ${leaked[0].split("/").pop()}` : "");
640	    check("[lab] reduced: zero console errors", consoleErrors.length === 0, consoleErrors[0] || "");
641	    await page.close();
642	  }
643	
644	  // (c) MOBILE 390px — static tier + zero horizontal overflow.
645	  {
646	    const page = await browser.newPage({ viewport: { width: 390, height: 844 }, hasTouch: true });
647	    const consoleErrors = [];
648	    page.on("console", (m) => m.type() === "error" && consoleErrors.push(m.text().slice(0, 300)));
649	    await page.goto(labUrl, { waitUntil: "load", timeout: 60000 });
