/**
 * useMotionStatic — the ONE static-tier gate every motion primitive applies
 * (scar #8). `true` ⇒ prefers-reduced-motion OR mobile viewport (< 768, the
 * same boundary as src/lib/useReducedMotion.js `isMobileViewport`). When true
 * a primitive renders its DESIGNED final/static state — never a blank, never
 * a mid-flight frame — and registers zero GSAP work.
 *
 * Reactive: tracks both media queries live, so a resize across the breakpoint
 * or an OS-level reduce toggle flips the tier without a reload.
 */
import { useEffect, useState } from "react";
import {
  prefersReducedMotion,
  isMobileViewport,
  isCoarsePointer,
  MOBILE_BREAKPOINT,
} from "../../lib/useReducedMotion.js";

export function useMotionStatic() {
  const [isStatic, setIsStatic] = useState(
    () => prefersReducedMotion() || isMobileViewport()
  );

  useEffect(() => {
    if (typeof window === "undefined" || !window.matchMedia) return undefined;
    const reduce = window.matchMedia("(prefers-reduced-motion: reduce)");
    const mobile = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`);
    const onChange = () => setIsStatic(reduce.matches || mobile.matches);
    reduce.addEventListener?.("change", onChange);
    mobile.addEventListener?.("change", onChange);
    return () => {
      reduce.removeEventListener?.("change", onChange);
      mobile.removeEventListener?.("change", onChange);
    };
  }, []);

  return isStatic;
}

/** Coarse-pointer gate for pointer-affordance primitives (Magnetic*): on touch
 *  they render plain tap targets — no magnet, no custom cursor. */
export function useCoarsePointer() {
  const [coarse, setCoarse] = useState(() => isCoarsePointer());
  useEffect(() => {
    if (typeof window === "undefined" || !window.matchMedia) return undefined;
    const mq = window.matchMedia("(pointer: coarse)");
    const onChange = () => setCoarse(mq.matches);
    mq.addEventListener?.("change", onChange);
    return () => mq.removeEventListener?.("change", onChange);
  }, []);
  return coarse;
}

