52	    const label = labelRef.current;
53	    if (!root || !label) return undefined;
54	
55	    const ctx = gsap.context(() => {
56	      // Built once — zero per-move allocations. SETTLE = weighty, non-elastic.
57	      const xTo = gsap.quickTo(root, "x", { duration: 0.4, ease: EASE.SETTLE });
58	      const yTo = gsap.quickTo(root, "y", { duration: 0.4, ease: EASE.SETTLE });
59	      const lxTo = gsap.quickTo(label, "x", { duration: 0.4, ease: EASE.SETTLE });
60	      const lyTo = gsap.quickTo(label, "y", { duration: 0.4, ease: EASE.SETTLE });
61	
62	      // Cached per enter (one getBoundingClientRect per enter — not per frame).
63	      let cx = 0;
64	      let cy = 0;
65	
66	      const onEnter = () => {
67	        const r = root.getBoundingClientRect();
68	        cx = r.left + r.width / 2;
69	        cy = r.top + r.height / 2;
