/**
 * MagneticButton — cuberto-style magnet (heavier retune for the rebuild).
 *
 * The root is pulled toward the cursor and an inner label span trails at half
 * the strength, giving a weighty, layered parallax. Movement is deliberate and
 * non-elastic (EASE.SETTLE only) — never bouncy. The rect is read once per
 * pointerenter; the per-move path allocates nothing (two pre-built quickTo
 * setters mutate the same two transforms).
 *
 * Props:
 *   as        string  "button" (default) | "a" | any tag. as="a" + href works.
 *   strength  number  0.35    root pull factor; label trails at strength*0.5.
 *   className string  ""      passthrough to the rendered element.
 *   children  node            label content (wrapped in the trailing span).
 *   ...rest                   forwarded to the element (href, onClick, type…).
 *
 * Gate (scar #8 + coarse): useCoarsePointer() OR useMotionStatic() ⇒ render a
 * plain element (normal tap target) with data-static="true" — zero GSAP, no
 * listeners, full magnet skipped. The designed final state of a magnet at rest
 * IS the plain button, so this is also the correct static frame.
 *
 * Reduced/mobile fallback: same as the gate above (plain element).
 *
 * Scars: #1 n/a (no ScrollTrigger). All GSAP inside the component's own
 * gsap.context scoped to the root ref; cleanup reverts + removes listeners
 * (idempotent under StrictMode double-mount). quickTo built once, EASE.SNAP
 * never used (transforms here settle, they don't overshoot). One
 * getBoundingClientRect per enter is allowed (not per-frame).
 */
import { useLayoutEffect, useRef } from "react";
import { gsap } from "gsap";
import { useCoarsePointer, useMotionStatic } from "./useMotionStatic.js";
import { DUR, EASE } from "../../lib/motion.js";

function MagneticButton({
  as = "button",
  strength = 0.35,
  className = "",
  children,
  ...rest
}) {
  const coarse = useCoarsePointer();
  const isStatic = useMotionStatic();
  const rootRef = useRef(null);
  const labelRef = useRef(null);

  const plain = coarse || isStatic;

  useLayoutEffect(() => {
    if (plain) return undefined;
    const root = rootRef.current;
    const label = labelRef.current;
    if (!root || !label) return undefined;

    const ctx = gsap.context(() => {
      // Built once — zero per-move allocations. SETTLE = weighty, non-elastic.
      const xTo = gsap.quickTo(root, "x", { duration: 0.4, ease: EASE.SETTLE });
      const yTo = gsap.quickTo(root, "y", { duration: 0.4, ease: EASE.SETTLE });
      const lxTo = gsap.quickTo(label, "x", { duration: 0.4, ease: EASE.SETTLE });
      const lyTo = gsap.quickTo(label, "y", { duration: 0.4, ease: EASE.SETTLE });

      // Cached per enter (one getBoundingClientRect per enter — not per frame).
      let cx = 0;
      let cy = 0;

      const onEnter = () => {
        const r = root.getBoundingClientRect();
        cx = r.left + r.width / 2;
        cy = r.top + r.height / 2;
      };
      const onMove = (e) => {
        const dx = e.clientX - cx;
        const dy = e.clientY - cy;
        xTo(dx * strength);
        yTo(dy * strength);
        lxTo(dx * strength * 0.5);
        lyTo(dy * strength * 0.5);
      };
      const onLeave = () => {
        gsap.to(root, { x: 0, y: 0, duration: DUR.MD, ease: EASE.SETTLE });
        gsap.to(label, { x: 0, y: 0, duration: DUR.MD, ease: EASE.SETTLE });
      };

      root.addEventListener("pointerenter", onEnter);
      root.addEventListener("pointermove", onMove);
      root.addEventListener("pointerleave", onLeave);

      return () => {
        root.removeEventListener("pointerenter", onEnter);
        root.removeEventListener("pointermove", onMove);
        root.removeEventListener("pointerleave", onLeave);
      };
    }, rootRef);

    return () => ctx.revert();
  }, [plain, strength]);

  const Tag = as;

  if (plain) {
    return (
      <Tag ref={rootRef} className={className} data-static="true" {...rest}>
        {children}
      </Tag>
    );
  }

  return (
    <Tag
      ref={rootRef}
      data-magnetic-button
      className={`inline-block will-change-transform ${className}`}
      {...rest}
    >
      <span ref={labelRef} className="inline-block will-change-transform">
        {children}
      </span>
    </Tag>
  );
}

export default MagneticButton;
export { MagneticButton };

