  src: url("/fonts/ClashDisplay-Semibold.woff2") format("woff2");
  font-weight: 600;
  font-style: normal;
  font-display: swap;
}
@font-face {
  font-family: "Clash Display";
  src: url("/fonts/ClashDisplay-Bold.woff2") format("woff2");
  font-weight: 700;
  font-style: normal;
  font-display: swap;
}
@font-face {
  font-family: "Satoshi";
  src: url("/fonts/Satoshi-Variable.woff2") format("woff2");
  font-weight: 400 700;
  font-style: normal;
  font-display: swap;
}
@font-face {
  font-family: "JetBrains Mono";
  src: url("/fonts/JetBrainsMono-Variable.woff2") format("woff2");
  font-weight: 400 500;
  font-style: normal;
  font-display: swap;
}

@tailwind base;
@tailwind components;
@tailwind utilities;

/* ---- Design tokens (TOKENS.md §1–§4). CSS-var prefix --k-. Single source the
   Tailwind theme keys point at. ---- */
:root {
  --k-ground: #0c0d10;
  --k-surface: #15171c;
  --k-surface-2: #101216;
  --k-line: #23262d;
  --k-line-2: #2e323b;
  --k-ink: #ede7da;
  --k-ink-dim: #c9c3b6;
  /* --k-muted bumped from #7c7f87 → #8d909a so mono labels/eyebrows clear WCAG
     AA (≥4.5:1) on bg-surface (#15171c), not just on ground. Hue/role identical
     (TOKENS.md §1 "mono dimension marks"); only luminance raised to pass the
     axe color-contrast gate (PROTOCOL §3, overrides the pinned hex). */
  --k-muted: #8d909a;
  --k-muted-2: #4a4d55;
  --k-accent: #3b7cff;
  --k-accent-strong: #2e63d6;
  --k-accent-soft: rgba(59, 124, 255, 0.14);

  --k-section-pad: clamp(6rem, 12vh, 10rem);
  --k-container: 1280px;
  --k-grid-cell: 48px;
}

/* Lenis smooth-scroll: native scroll-behavior must be off so Lenis can drive it
   (wired in S03). Reduced-motion path leaves native scrolling on. */
html.lenis,
html.lenis body {
  height: auto;
}
.lenis.lenis-smooth {
  scroll-behavior: auto !important;
}
.lenis.lenis-smooth [data-lenis-prevent] {
  overscroll-behavior: contain;
}
.lenis.lenis-stopped {
  overflow: hidden;
}
@media (prefers-reduced-motion: reduce) {
  html {
    scroll-behavior: smooth;
  }
}

html,
body {
  overflow-x: clip;
}

body {
  font-family: "Satoshi", system-ui, sans-serif;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  background-color: var(--k-ground);
  color: var(--k-ink);
  line-height: 1.7;
}

/* Mono numerals are always tabular (TOKENS.md §2). */
.font-mono {
  font-variant-numeric: tabular-nums;
}

/* Scrollbar — graphite track, blueprint-line thumb. */
::-webkit-scrollbar {
  width: 6px;
}
::-webkit-scrollbar-track {
  background: var(--k-ground);
}
::-webkit-scrollbar-thumb {
  background: var(--k-line-2);
  border-radius: 9999px;
}
::-webkit-scrollbar-thumb:hover {
  background: var(--k-accent);
}

::selection {
  background: var(--k-accent-soft);
  color: var(--k-ink);
}

@media (prefers-reduced-motion: reduce) {
  /* Safety net: neutralize long/looping animations & transitions. */
  *,
  *::before,
  *::after {
    animation-duration: 0.001ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.001ms !important;
    scroll-behavior: auto !important;
  }
}

          ))}
        </div>
      </StubSection>

      {/* H6 CTA banner — reaches #newsletter in the footer (cross-section anchor). */}
      <StubSection id="cta" eyebrow="Next step" title={CTA_BANNER.headline}>
        <p className="max-w-2xl font-body text-ink-dim">{CTA_BANNER.subtitle}</p>
        <div className="mt-6 flex flex-wrap gap-4">
          <a
            href="#newsletter"
            className="rounded-sm bg-accent px-5 py-3 font-body text-sm font-medium text-ground transition-colors hover:brightness-110"
          >
            {CTA_BANNER.button}
          </a>
          <a
            href={LINKS.calendly}
            target="_blank"
            rel="noopener noreferrer"
            className="rounded-sm border border-line-2 px-5 py-3 font-body text-sm font-medium text-ink transition-colors hover:border-accent"
          >
            Book a call
          </a>
        </div>
        <ul className="mt-6 flex flex-wrap gap-3">
          {CTA_BANNER.badges.map((b) => (
            <li key={b} className="font-mono text-mono-trace text-muted">
              {b}
            </li>
          ))}
        </ul>
      </StubSection>
    </div>
  );
}

