import { BRAND } from "../../data/brand.js";

/**
 * Wordmark — the "kartarAI" brand mark (S05), derived from BRAND.wordmark
 * (LOCKED fact). Drafting-table treatment: bone display type with the "AI"
 * inked in the one accent. No saffron pill (forbidden palette — anti-wander
 * rule 1); the accent glyph is part of the <=10% accent budget per frame.
 */
export default function Wordmark({ className = "" }) {
  const base = BRAND.wordmark.replace(/AI$/, "");
  return (
    <span className={`font-display font-bold leading-none text-ink ${className}`}>
      {base}
      <span className="text-accent">AI</span>
    </span>
  );
}

