import { prefersReducedMotion } from "./useReducedMotion.js";

/**
 * goToNewsletter — THE shared CTA→newsletter helper (S05, locked behavior).
 *
 * The newsletter signup (#newsletter + the Sender mount) lives in the GLOBAL
 * footer, so it exists on every route — no route change is needed; the helper
 * works from anywhere and lands the viewport on the form.
 *
 * Robustness order:
 *   1. Lenis (window.__lenis) when the smooth tier is active.
 *   2. scrollIntoView fallback (native tiers / Lenis not ready), instant under
 *      prefers-reduced-motion.
 *
 * Returns true when #newsletter was found and a scroll was issued.
 * S06's CtaBanner (and any "Deploy your first agent" CTA) imports this —
 * never hand-roll the scroll.
 */
export function goToNewsletter() {
  const el = document.getElementById("newsletter");
  if (!el) return false;
  if (window.__lenis) {
    window.__lenis.scrollTo(el, { offset: -24 });
  } else {
    el.scrollIntoView({
      behavior: prefersReducedMotion() ? "auto" : "smooth",
      block: "start",
    });
  }
  return true;
}

// Dev/QA hook: verify.mjs invokes the helper through this global to assert the
// locked CTA→newsletter behavior. Dev-only — DCE'd from prod builds.
if (import.meta.env?.DEV && typeof window !== "undefined") {
  window.__goToNewsletter = goToNewsletter;
}

