/**
 * Navbar — the persistent router-aware chrome (S05).
 *
 * - Links are <NavLink> rows from the ONE nav source (src/data/nav.js);
 *   mono drafting-label styling with an accent rule under the active route.
 * - Calendly CTA reads LINKS.calendly (one constant, never a literal) and is
 *   a MagneticButton on fine pointers (plain tap target on coarse/static).
 * - Condense-on-scroll via ONE shell-level ScrollTrigger (start 64px → "max")
 *   that flips a single data attribute at the boundary — zero per-frame work,
 *   no rogue rAF, no scroll listener.
 *
 * SHELL-LEVEL LIFECYCLE WARNING (scar #9 awareness): the Navbar persists
 * across routes, so its trigger lives in this component's OWN gsap.context —
 * NEVER inside useRouteScrollContext. A per-route context would revert the
 * trigger on the first navigation and freeze the navbar's scroll state.
 *
 * Mobile (<=768): hamburger menu, conditional render = instant open/close
 * (the index.css reduced-motion safety net keeps any transition instant);
 * all 4 routes + the Calendly CTA stay reachable as plain tap targets.
 */
import { useLayoutEffect, useRef, useState } from "react";
import { Link, NavLink } from "react-router-dom";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { NAV } from "../../data/nav.js";
import { LINKS } from "../../data/links.js";
import MagneticButton from "../motion/MagneticButton.jsx";
import Wordmark from "./Wordmark.jsx";

gsap.registerPlugin(ScrollTrigger);

const linkClass = ({ isActive }) =>
  `group/link relative py-1 font-mono text-[0.6875rem] uppercase tracking-[0.12em] transition-colors ${
    isActive ? "text-ink" : "text-muted hover:text-ink"
  }`;

export default function Navbar() {
  const rootRef = useRef(null);
  const [open, setOpen] = useState(false);
  const close = () => setOpen(false);

  useLayoutEffect(() => {
    const root = rootRef.current;
    if (!root) return undefined;
    const ctx = gsap.context(() => {
      const st = ScrollTrigger.create({
        id: "navbar-condense",
        start: 64,
        end: "max",
        onToggle: (self) =>
          root.toggleAttribute("data-condensed", self.isActive),
      });
      // Cover a load that starts mid-page (?jump, deep anchors): onToggle only
      // fires on CHANGE, so commit the initial state explicitly.
      root.toggleAttribute("data-condensed", st.isActive);
    });
    return () => ctx.revert();
  }, []);

  return (
    <header
      ref={rootRef}
      className="group sticky top-0 z-50 border-b border-line bg-ground/90 backdrop-blur transition-colors duration-300 data-[condensed]:bg-ground/95"
    >
      <nav
        aria-label="Primary"
        className="mx-auto max-w-[1280px] px-[clamp(1.25rem,4vw,3rem)]"
      >
        <div className="flex items-center justify-between gap-4 py-5 transition-[padding] duration-300 group-data-[condensed]:py-3">
          <Link to="/" onClick={close} className="shrink-0" data-cursor="magnet">
            <Wordmark className="text-lg" />
          </Link>

          {/* Desktop route links */}
          <div className="hidden items-center gap-8 md:flex">
            {NAV.map((item, i) => (
              <NavLink
                key={item.to}
                to={item.to}
                end={item.to === "/"}
                className={linkClass}
              >
                {({ isActive }) => (
                  <>
                    <span className="mr-1.5 text-muted" aria-hidden="true">
                      {String(i + 1).padStart(2, "0")}
                    </span>
                    {item.label}
                    <span
                      aria-hidden="true"
                      className={`absolute -bottom-1 left-0 h-px w-full transition-colors ${
                        isActive
                          ? "bg-accent"
                          : "bg-transparent group-hover/link:bg-line-2"
                      }`}
                    />
                  </>
                )}
              </NavLink>
            ))}
          </div>

          <div className="flex items-center gap-3">
            <MagneticButton
              as="a"
              href={LINKS.calendly}
              target="_blank"
              rel="noopener noreferrer"
              data-cursor="magnet"
              className="!hidden rounded-sm bg-accent px-4 py-2 font-body text-sm font-medium text-ground transition-colors hover:bg-accent-strong md:!inline-block"
            >
              Book a call
            </MagneticButton>

            {/* Mobile menu toggle */}
            <button
              type="button"
              data-nav-toggle
              aria-expanded={open}
              aria-controls="mobile-menu"
              aria-label={open ? "Close menu" : "Open menu"}
              onClick={() => setOpen((v) => !v)}
              className="-mr-1 rounded-sm p-2 text-ink md:hidden"
            >
              <svg width="20" height="20" viewBox="0 0 20 20" fill="none" aria-hidden="true">
                {open ? (
                  <path d="M4 4l12 12M16 4L4 16" stroke="currentColor" strokeWidth="1.5" />
                ) : (
                  <path d="M2 6h16M2 10h16M2 14h10" stroke="currentColor" strokeWidth="1.5" />
                )}
              </svg>
            </button>
          </div>
        </div>
      </nav>

      {/* Mobile menu — instant toggle; numbered drafting rows. */}
      {open && (
        <div id="mobile-menu" className="border-t border-line bg-ground md:hidden">
          <div className="mx-auto flex max-w-[1280px] flex-col px-[clamp(1.25rem,4vw,3rem)] py-4">
            {NAV.map((item, i) => (
              <NavLink
                key={item.to}
                to={item.to}
                end={item.to === "/"}
                onClick={close}
                className={({ isActive }) =>
                  `border-b border-line py-3 font-mono text-[0.6875rem] uppercase tracking-[0.12em] ${
                    isActive ? "text-ink" : "text-muted"
                  }`
                }
              >
                <span className="mr-3 text-muted" aria-hidden="true">
                  {String(i + 1).padStart(2, "0")}
                </span>
                {item.label}
              </NavLink>
            ))}
            <a
              href={LINKS.calendly}
              target="_blank"
              rel="noopener noreferrer"
              onClick={close}
              className="mt-4 rounded-sm bg-accent px-4 py-3 text-center font-body text-sm font-medium text-ground"
            >
              Book a call
            </a>
          </div>
        </div>
      )}
    </header>
  );
}

