          {/* Desktop route links */}
          <div className="hidden items-center gap-8 md:flex">
            {NAV.map((item, i) => (
              <NavLink
                key={item.to}
                to={item.to}
                end={item.to === "/"}
                className={linkClass}
              >
                {({ isActive }) => (
                  <>
                    <span className="mr-1.5 text-muted" aria-hidden="true">
                      {String(i + 1).padStart(2, "0")}
                    </span>
                    {item.label}
                    <span
                      aria-hidden="true"
                      className={`absolute -bottom-1 left-0 h-px w-full transition-colors ${
                        isActive
                          ? "bg-accent"
                          : "bg-transparent group-hover/link:bg-line-2"
                      }`}
                    />
                  </>
                )}
              </NavLink>
            ))}
          </div>

          <div className="flex items-center gap-3">
            <MagneticButton
              as="a"
              href={LINKS.calendly}
              target="_blank"
              rel="noopener noreferrer"
              data-cursor="magnet"
              className="!hidden rounded-sm bg-accent px-4 py-2 font-body text-sm font-medium text-ground transition-colors hover:bg-accent-strong md:!inline-block"
            >
              Book a call
            </MagneticButton>

            {/* Mobile menu toggle */}
            <button
              type="button"
              data-nav-toggle
              aria-expanded={open}
              aria-controls="mobile-menu"
              aria-label={open ? "Close menu" : "Open menu"}
              onClick={() => setOpen((v) => !v)}
              className="-mr-1 rounded-sm p-2 text-ink md:hidden"
            >
              <svg width="20" height="20" viewBox="0 0 20 20" fill="none" aria-hidden="true">
                {open ? (
                  <path d="M4 4l12 12M16 4L4 16" stroke="currentColor" strokeWidth="1.5" />
                ) : (
                  <path d="M2 6h16M2 10h16M2 14h10" stroke="currentColor" strokeWidth="1.5" />
                )}
              </svg>
            </button>
          </div>
        </div>
      </nav>

      {/* Mobile menu — instant toggle; numbered drafting rows. */}
      {open && (
        <div id="mobile-menu" className="border-t border-line bg-ground md:hidden">
          <div className="mx-auto flex max-w-[1280px] flex-col px-[clamp(1.25rem,4vw,3rem)] py-4">
            {NAV.map((item, i) => (
              <NavLink
                key={item.to}
                to={item.to}
                end={item.to === "/"}
                onClick={close}
                className={({ isActive }) =>
                  `border-b border-line py-3 font-mono text-[0.6875rem] uppercase tracking-[0.12em] ${
                    isActive ? "text-ink" : "text-muted"
                  }`
                }
              >
                <span className="mr-3 text-muted" aria-hidden="true">
                  {String(i + 1).padStart(2, "0")}
                </span>
                {item.label}
              </NavLink>
            ))}
            <a
              href={LINKS.calendly}
              target="_blank"
              rel="noopener noreferrer"
              onClick={close}
              className="mt-4 rounded-sm bg-accent px-4 py-3 text-center font-body text-sm font-medium text-ground"
            >
              Book a call
            </a>
          </div>
        </div>
      )}
    </header>
  );
}

