import { useState } from "react";
import { useLocation, useOutlet } from "react-router-dom";
import { AnimatePresence, motion } from "framer-motion";
import Navbar from "../components/chrome/Navbar.jsx";
import Footer from "../components/chrome/Footer.jsx";
import CustomCursor from "../components/chrome/CustomCursor.jsx";
import Preloader from "../components/Preloader.jsx";

/**
 * FrozenOutlet — captures the outlet element ONCE at mount. AnimatePresence
 * keeps the exiting seam child in the tree during a route swap; a live
 * <Outlet/> inside it would re-render the NEW route's element (router context
 * propagates into frozen children), double-mounting the page. Freezing the
 * element keeps the exiting seam rendering the OLD page until it unmounts —
 * which also preserves the scar-#9 ordering (old route's gsap.context reverts
 * before the new route's effects run).
 */
function FrozenOutlet() {
  const outlet = useOutlet();
  const [frozen] = useState(outlet);
  return frozen;
}

/**
 * RootLayout — the app shell every route renders inside (S05):
 * CustomCursor (gated) + Navbar + transition-seam-wrapped outlet + Footer.
 * Routed page content mounts in the seam BETWEEN Navbar and Footer.
 *
 * THE SEAM IS A NO-OP this sprint: AnimatePresence mode="wait" keyed on
 * pathname, no animation props — instant swap. S13 fills the chapter-wipe.
 *
 * Scar #2 (binding): the seam wrapper [data-route-seam] must NEVER become a
 * scroll container — no transform, no overflow, no fixed height. Lenis scrolls
 * the REAL window. The wipe surface S13 adds is an `absolute inset-0` OVERLAY
 * on the relative <main> below (scar #4 host), never a wrapper around the
 * Outlet.
 */
export default function RootLayout() {
  const location = useLocation();
  return (
    <div className="relative min-h-screen bg-ground text-ink">
      <Preloader />
      <CustomCursor />
      <Navbar />
      {/* main is position:relative — the S13 wipe-overlay host (scar #4). */}
      <main id="main" className="relative">
        {/* ================================================================
            S13 TRANSITION HOOK POINT (blueprint-paper chapter-wipe, <=700ms):
            - The wipe surface mounts HERE as an `absolute inset-0` overlay on
              this <main> — an OVERLAY, never a transformed/overflow wrapper
              around the Outlet (scar #2).
            - Give the seam child exit/enter animations; at cover-peak
              ("covered") call lenis.scrollTo(0, { immediate: true }) +
              refreshSoon() (src/lib/useRouteScrollContext.js). The trigger
              KILL stays in useRouteScrollContext's revert — the seam itself
              never kills triggers (scar #9 split of responsibilities).
            - Gate on window.__preloaderDone / the "preloaderDone" event,
              never on the preloader node existing.
            - Reduced motion: instant cross-fade <=200ms.
           ================================================================ */}
        <AnimatePresence mode="wait" initial={false}>
          <motion.div key={location.pathname} data-route-seam>
            <FrozenOutlet />
          </motion.div>
        </AnimatePresence>
      </main>
      <Footer />
    </div>
  );
}

