import { Outlet } from "react-router-dom";
import StubNav from "./StubNav.jsx";
import StubFooter from "./StubFooter.jsx";
import Preloader from "../components/Preloader.jsx";

// Layout route: nav + routed Outlet + footer. The Outlet wrapper is a PLAIN
// block — NOT a transformed scroll container (scar #2). Lenis scrolls the real
// window. The page-transition seam (chapter-wipe overlay) is S05/S13's job and
// must remain an overlay, never wrap the Outlet in a transform.
// Preloader (S03) lives here — the layout route persists across navigations,
// so it mounts once per hard load; the sessionStorage gate keeps it to once
// per session.
export default function RootLayout() {
  return (
    <div className="relative min-h-screen bg-ground text-ink">
      <Preloader />
      <StubNav />
      <main id="main">
        <Outlet />
      </main>
      <StubFooter />
    </div>
  );
}

