        readout: document.querySelector("[data-lab-progress]")?.textContent.trim(),
        hasText: document.body.innerText.trim().length > 400,
      };
    }, LAB_BLOCKS);
    check("[lab] reduced: static fallbacks rendered (>= 11 blocks)", r.blocksWithStatic >= 11, `(${r.blocksWithStatic})`);
    check("[lab] reduced: zero pins", r.pinSpacers === 0, `(${r.pinSpacers})`);
    check("[lab] reduced: no custom cursor", !r.cursor);
    check("[lab] reduced: SplitLines static text fully readable", r.splitText);
    check("[lab] reduced: InkReveal final state visible", r.inkVisible);
    check(
      "[lab] reduced: CountStrike shows final numbers immediately",
