export const meta = {
  name: 'sprint-05-gate-audit',
  description: 'Fresh-eyes visual audit + adversarial scar-compliance review for sprint 05 chrome',
  phases: [
    { title: 'Audit', detail: 'visual auditor + scar reviewer in parallel' },
  ],
}

const AUDIT_SCHEMA = {
  type: "object",
  required: ["verdict", "findings"],
  properties: {
    verdict: { type: "string", enum: ["SHIP", "FIX"] },
    findings: {
      type: "array",
      items: {
        type: "object",
        required: ["frame", "finding", "severity"],
        properties: {
          frame: { type: "string" },
          finding: { type: "string" },
          severity: { type: "string", enum: ["FIX", "watch"] },
        },
      },
    },
  },
}

const REVIEW_SCHEMA = {
  type: "object",
  required: ["verdict", "findings"],
  properties: {
    verdict: { type: "string", enum: ["PASS", "FAIL"] },
    findings: {
      type: "array",
      items: {
        type: "object",
        required: ["file", "finding", "severity"],
        properties: {
          file: { type: "string" },
          finding: { type: "string" },
          severity: { type: "string", enum: ["blocking", "watch"] },
        },
      },
    },
  },
}

phase('Audit')

const [visual, scars] = await parallel([
  () => agent(`You are a FRESH-EYES visual auditor for a website rebuild. You have NO knowledge of how it was built and must NOT rationalize choices — judge only what you see.

Repo root: /Users/prynq/Desktop/kartar/sachmeetsb.github.io

Read FIRST (the binding art direction):
- plans/design/DIRECTION.md
- plans/design/TOKENS.md

Then OPEN AND LOOK AT EVERY ONE of the 56 screenshot frames in /tmp/shots/sprint-05/ (use the Read tool on each .png — desktop, mobile, lab, preloader). Do not skip frames.

Context you may use: this is sprint 05 of 17 — the global chrome sprint (navbar, footer, custom cursor). The page BODIES are still data-complete stubs (sections render real content but final motion/art comes in sprints 06-09), so judge stub bodies leniently; judge the NAVBAR (top of frames) and FOOTER (bottom frames, the newsletter/contact/navigation columns) STRICTLY — those are this sprint's deliverable.

Checklist — judge every frame on:
1. Readability — all text legible at rendered size; nothing cut off, overlapped, or badly wrapped; sane line lengths.
2. Contrast & hierarchy — foreground/background separation obvious; one clear focal point per viewport; type scale reads eyebrow -> heading -> body.
3. Spacing rhythm — consistent section padding; nothing crammed or orphaned; the grid holds.
4. Motion end-states — nothing stuck mid-animation, half-revealed, or stranded below opacity 1 in settled frames.
5. Direction fidelity — frames look like DIRECTION.md's "Blueprint -> Built" route (graphite ground, bone ink, ONE blueprint-blue accent <=10% of frame, mono drafting labels), not generic dark-SaaS. No forbidden colors (saffron #F2A93B, indigo, teal, ember).
6. Mobile dignity — mobile frames are a designed experience, not a squeezed desktop; navbar/footer usable at 390px.

Return verdict SHIP or FIX. Each finding: frame filename, what is wrong, severity "FIX" (must fix before ship) or "watch" (acceptable, note it). An empty findings array with SHIP means everything is clean.`, { label: 'visual-audit', phase: 'Audit', schema: AUDIT_SCHEMA }),

  () => agent(`You are an adversarial code reviewer for sprint 05 of a website rebuild. Your ONLY job: try to find violations of the project's hard rules ("scars") in the uncommitted diff. Default to skeptical — but report only REAL violations you can argue from the code, with file:line.

Repo root: /Users/prynq/Desktop/kartar/sachmeetsb.github.io (branch feat/rebuild-2026).

First read plans/PROTOCOL.md section 2 (THE 10 SCARS) and section 9. Then review the working-tree diff: run "git status --porcelain" and "git diff HEAD" and read the NEW files git diff misses (src/components/chrome/*.jsx, src/lib/goToNewsletter.js).

Hunt specifically for:
- Scar #2: does the transition seam wrapper in src/pages/RootLayout.jsx (or anything else) create a transformed/overflow scroll container around the routed content? Check what framer-motion's AnimatePresence/motion.div could apply.
- Scar #7 / StrictMode: is the Sender polling-render in src/components/chrome/Footer.jsx idempotent under double-invoke (no double form render, no leaked timer, clean remount)? Is the Navbar's ScrollTrigger effect idempotent?
- Scar #9: is the Navbar's ScrollTrigger registered at SHELL level (its own gsap.context) and NOT inside useRouteScrollContext? Would anything kill it on navigation? Conversely, does the FrozenOutlet pattern in RootLayout preserve "old route's triggers die BEFORE new page mounts"?
- Scar #10: any standalone requestAnimationFrame loops, per-frame allocations, per-frame getBoundingClientRect, or setState-per-frame in the new chrome?
- Gating: CustomCursor must render nothing on coarse pointer / mobile (<768) / prefers-reduced-motion. MagneticButton fallback must stay a plain tap target.
- Hardcoded facts: any Calendly/email/LinkedIn/Sender/EmailJS literal in a component instead of reading src/data/links.js or src/data/nav.js.
- The deleted StubNav/StubFooter: anything still importing them?
- Anything in the verify.mjs changes that weakens an existing assertion.

Return verdict PASS (no blocking violations) or FAIL, with findings: file, what is wrong + why it violates which scar, severity "blocking" or "watch".`, { label: 'scar-review', phase: 'Audit', schema: REVIEW_SCHEMA }),
])

return { visual, scars }

