/**
 * Footer — global chrome, mounted in RootLayout below the routed Outlet, so it
 * renders on EVERY route. Hosts THE locked integrations:
 *   - #newsletter — the one hard cross-route anchor the CTA banner targets
 *     (reached via src/lib/goToNewsletter.js).
 *   - the Sender.net mount [data-sender-form-id="axkAXn"] + polling render
 *     (form id + account from LINKS — never literals).
 *   - the ONE company LinkedIn link, mailto, a Calendly CTA, NAV links (the
 *     same single source the Navbar consumes).
 *
 * Blueprint title-block treatment: mono column labels over hairline rules,
 * bone text on the recessed surface, a registration-mark bottom row.
 */
import { useEffect, useRef } from "react";
import { Link } from "react-router-dom";
import { NAV } from "../../data/nav.js";
import { LINKS } from "../../data/links.js";
import { BRAND } from "../../data/brand.js";
import Wordmark from "./Wordmark.jsx";

const colLabel =
  "font-mono text-[0.6875rem] uppercase tracking-[0.12em] text-muted";

export default function Footer() {
  const senderMountRef = useRef(null);

  // Sender polling-render lifecycle — LOCKED pattern salvaged from main's
  // Footer. The universal script (index.html) loads with ?explicit=true, so it
  // does NOT auto-render forms on scan; we render manually once the mount
  // exists, polling until the script has loaded (setTimeout, never a rAF).
  // StrictMode-safe (scar #7): the cancelled flag stops a pending poll; cleanup
  // destroys the rendered form AND clears the injected nodes so the second
  // dev-mount re-renders into a clean container. The form only ever renders
  // into the ONE [data-sender-form-id] mount below.
  useEffect(() => {
    let cancelled = false;
    let timer = null;
    const mount = senderMountRef.current;

    const tryRender = (attempt = 0) => {
      if (cancelled) return;
      if (window.senderForms && typeof window.senderForms.render === "function") {
        window.senderForms.render(LINKS.sender.formId);
      } else if (attempt < 50) {
        timer = setTimeout(() => tryRender(attempt + 1), 100);
      }
    };
    tryRender();

    return () => {
      cancelled = true;
      if (timer) clearTimeout(timer);
      if (window.senderForms && typeof window.senderForms.destroy === "function") {
        window.senderForms.destroy(LINKS.sender.formId);
      }
      if (mount) mount.replaceChildren();
    };
  }, []);

  return (
    <footer className="border-t border-line bg-surface-2 text-ink-dim">
      <div className="mx-auto max-w-[1280px] px-[clamp(1.25rem,4vw,3rem)] py-16">
        <div className="grid gap-12 md:grid-cols-2 lg:grid-cols-[1.4fr_1fr_1fr_1.4fr]">
          {/* Brand block */}
          <div>
            <Link to="/" data-cursor="magnet">
              <Wordmark className="text-lg" />
            </Link>
            <p className="mt-4 max-w-xs font-body text-sm leading-[1.7] text-ink-dim">
              {BRAND.name}. Agentic AI systems and AI-native products, drafted
              and built for how India actually works.
            </p>
          </div>

          {/* Navigation — same NAV source as the Navbar */}
          <nav aria-label="Footer">
            <h2 className={`${colLabel} border-b border-line pb-3`}>
              Navigation
            </h2>
            <ul className="mt-4 flex flex-col gap-2.5">
              {NAV.map((item, i) => (
                <li key={item.to}>
                  <Link
                    to={item.to}
                    className="font-body text-sm text-ink-dim transition-colors hover:text-ink"
                  >
                    <span className="mr-2 font-mono text-[0.6875rem] text-muted" aria-hidden="true">
                      {String(i + 1).padStart(2, "0")}
                    </span>
                    {item.label}
                  </Link>
                </li>
              ))}
            </ul>
          </nav>

          {/* Contact */}
          <div>
            <h2 className={`${colLabel} border-b border-line pb-3`}>Contact</h2>
            <ul className="mt-4 flex flex-col gap-2.5 font-body text-sm">
              <li>
                <a
                  href={`mailto:${LINKS.email}`}
                  className="text-ink-dim transition-colors hover:text-ink"
                >
                  {LINKS.email}
                </a>
              </li>
              <li>
                <a
                  href={LINKS.calendly}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-ink-dim transition-colors hover:text-ink"
                >
                  Book a call
                </a>
              </li>
              <li>
                <a
                  href={LINKS.linkedinCompany}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-ink-dim transition-colors hover:text-ink"
                >
                  LinkedIn
                </a>
              </li>
            </ul>
          </div>

          {/* #newsletter — the locked cross-route anchor + Sender mount. */}
          <section id="newsletter" aria-labelledby="newsletter-title">
            <h2
              id="newsletter-title"
              className={`${colLabel} border-b border-line pb-3`}
            >
              Updates
            </h2>
            <p className="mt-4 font-body text-sm text-ink-dim">
              Get updates. No spam. Just builds.
            </p>
            <div
              ref={senderMountRef}
              className="sender-form-field mt-4"
              data-sender-form-id={LINKS.sender.formId}
            />
          </section>
        </div>

        {/* Title-block bottom row */}
        <div className="mt-14 flex flex-wrap items-center justify-between gap-3 border-t border-line pt-6">
          <p className="font-mono text-[0.6875rem] uppercase tracking-[0.12em] text-muted">
            © {new Date().getFullYear()} {BRAND.name}. All rights reserved.
          </p>
          <p className="font-mono text-[0.6875rem] uppercase tracking-[0.12em] text-muted" aria-hidden="true">
            {BRAND.domain} · sheet 01 · rev 2026
          </p>
        </div>
      </div>
    </footer>
  );
}

/**
 * Navbar — the persistent router-aware chrome (S05).
 *
 * - Links are <NavLink> rows from the ONE nav source (src/data/nav.js);
 *   mono drafting-label styling with an accent rule under the active route.
 * - Calendly CTA reads LINKS.calendly (one constant, never a literal) and is
 *   a MagneticButton on fine pointers (plain tap target on coarse/static).
 * - Condense-on-scroll via ONE shell-level ScrollTrigger (start 64px → "max")
 *   that flips a single data attribute at the boundary — zero per-frame work,
 *   no rogue rAF, no scroll listener.
 *
 * SHELL-LEVEL LIFECYCLE WARNING (scar #9 awareness): the Navbar persists
 * across routes, so its trigger lives in this component's OWN gsap.context —
 * NEVER inside useRouteScrollContext. A per-route context would revert the
 * trigger on the first navigation and freeze the navbar's scroll state.
 *
 * Mobile (<=768): hamburger menu, conditional render = instant open/close
 * (the index.css reduced-motion safety net keeps any transition instant);
 * all 4 routes + the Calendly CTA stay reachable as plain tap targets.
 */
import { useLayoutEffect, useRef, useState } from "react";
import { Link, NavLink } from "react-router-dom";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { NAV } from "../../data/nav.js";
import { LINKS } from "../../data/links.js";
import MagneticButton from "../motion/MagneticButton.jsx";
import Wordmark from "./Wordmark.jsx";

gsap.registerPlugin(ScrollTrigger);

const linkClass = ({ isActive }) =>
  `group/link relative py-1 font-mono text-[0.6875rem] uppercase tracking-[0.12em] transition-colors ${
    isActive ? "text-ink" : "text-muted hover:text-ink"
  }`;

export default function Navbar() {
  const rootRef = useRef(null);
  const [open, setOpen] = useState(false);
  const close = () => setOpen(false);

  useLayoutEffect(() => {
    const root = rootRef.current;
    if (!root) return undefined;
    const ctx = gsap.context(() => {
      const st = ScrollTrigger.create({
        id: "navbar-condense",
        start: 64,
        end: "max",
        onToggle: (self) =>
          root.toggleAttribute("data-condensed", self.isActive),
      });
      // Cover a load that starts mid-page (?jump, deep anchors): onToggle only
      // fires on CHANGE, so commit the initial state explicitly.
      root.toggleAttribute("data-condensed", st.isActive);
    });
    return () => ctx.revert();
  }, []);

  return (
    <header
      ref={rootRef}
      className="group sticky top-0 z-50 border-b border-line bg-ground/90 backdrop-blur transition-colors duration-300 data-[condensed]:bg-ground/95"
    >
      <nav
        aria-label="Primary"
        className="mx-auto max-w-[1280px] px-[clamp(1.25rem,4vw,3rem)]"
      >
        <div className="flex items-center justify-between gap-4 py-5 transition-[padding] duration-300 group-data-[condensed]:py-3">
          <Link to="/" onClick={close} className="shrink-0" data-cursor="magnet">
            <Wordmark className="text-lg" />
          </Link>

          {/* Desktop route links */}
          <div className="hidden items-center gap-8 md:flex">
            {NAV.map((item, i) => (
              <NavLink
                key={item.to}
                to={item.to}
                end={item.to === "/"}
                className={linkClass}
              >
                {({ isActive }) => (
                  <>
                    <span className="mr-1.5 text-muted" aria-hidden="true">
                      {String(i + 1).padStart(2, "0")}
                    </span>
                    {item.label}
                    <span
                      aria-hidden="true"
                      className={`absolute -bottom-1 left-0 h-px w-full transition-colors ${
                        isActive
                          ? "bg-accent"
                          : "bg-transparent group-hover/link:bg-line-2"
                      }`}
                    />
                  </>
                )}
              </NavLink>
            ))}
          </div>

          <div className="flex items-center gap-3">
            <MagneticButton
              as="a"
              href={LINKS.calendly}
              target="_blank"
              rel="noopener noreferrer"
              data-cursor="magnet"
              className="!hidden rounded-sm bg-accent px-4 py-2 font-body text-sm font-medium text-ground transition-colors hover:bg-accent-strong md:!inline-block"
            >
              Book a call
            </MagneticButton>

            {/* Mobile menu toggle */}
            <button
              type="button"
              data-nav-toggle
              aria-expanded={open}
              aria-controls="mobile-menu"
              aria-label={open ? "Close menu" : "Open menu"}
              onClick={() => setOpen((v) => !v)}
              className="-mr-1 rounded-sm p-2 text-ink md:hidden"
            >
              <svg width="20" height="20" viewBox="0 0 20 20" fill="none" aria-hidden="true">
                {open ? (
                  <path d="M4 4l12 12M16 4L4 16" stroke="currentColor" strokeWidth="1.5" />
                ) : (
                  <path d="M2 6h16M2 10h16M2 14h10" stroke="currentColor" strokeWidth="1.5" />
                )}
              </svg>
            </button>
          </div>
        </div>
      </nav>

      {/* Mobile menu — instant toggle; numbered drafting rows. */}
      {open && (
        <div id="mobile-menu" className="border-t border-line bg-ground md:hidden">
          <div className="mx-auto flex max-w-[1280px] flex-col px-[clamp(1.25rem,4vw,3rem)] py-4">
            {NAV.map((item, i) => (
              <NavLink
                key={item.to}
                to={item.to}
                end={item.to === "/"}
                onClick={close}
                className={({ isActive }) =>
                  `border-b border-line py-3 font-mono text-[0.6875rem] uppercase tracking-[0.12em] ${
                    isActive ? "text-ink" : "text-muted"
                  }`
                }
              >
                <span className="mr-3 text-muted" aria-hidden="true">
                  {String(i + 1).padStart(2, "0")}
                </span>
                {item.label}
              </NavLink>
            ))}
            <a
              href={LINKS.calendly}
              target="_blank"
              rel="noopener noreferrer"
              onClick={close}
              className="mt-4 rounded-sm bg-accent px-4 py-3 text-center font-body text-sm font-medium text-ground"
            >
              Book a call
            </a>
          </div>
        </div>
      )}
    </header>
  );
}

