  let path = "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome";
  if (!fs.existsSync(path)) path = chromium.executablePath();
  const b = await chromium.launch({ executablePath: path, headless: true });
  for (const [name, vp] of [["fix-footer-desktop", { width: 1440, height: 900 }], ["fix-footer-mobile", { width: 390, height: 844 }]]) {
    const p = await b.newPage({ viewport: vp });
    await p.goto("http://localhost:5173/?skippreload", { waitUntil: "load" });
    await p.waitForTimeout(5000);
    await p.evaluate(() => {
      const max = document.documentElement.scrollHeight - window.innerHeight;
      if (window.__lenis) window.__lenis.scrollTo(max, { immediate: true });
      else window.scrollTo(0, max);
    });
    await p.waitForTimeout(2000);
    await p.screenshot({ path: `/tmp/shots/sprint-05/${name}.png` });
    await p.close();
  }
  await b.close();
  console.log("done");
});'

