/**
 * Footer — global chrome, mounted in RootLayout below the routed Outlet, so it
 * renders on EVERY route. Hosts THE locked integrations:
 *   - #newsletter — the one hard cross-route anchor the CTA banner targets
 *     (reached via src/lib/goToNewsletter.js).
 *   - the Sender.net mount [data-sender-form-id="axkAXn"] + polling render
 *     (form id + account from LINKS — never literals).
 *   - the ONE company LinkedIn link, mailto, a Calendly CTA, NAV links (the
 *     same single source the Navbar consumes).
 *
 * Blueprint title-block treatment: mono column labels over hairline rules,
 * bone text on the recessed surface, a registration-mark bottom row.
 */
import { useEffect, useRef } from "react";
import { Link } from "react-router-dom";
import { NAV } from "../../data/nav.js";
import { LINKS } from "../../data/links.js";
import { BRAND } from "../../data/brand.js";
import Wordmark from "./Wordmark.jsx";

const colLabel =
  "font-mono text-[0.6875rem] uppercase tracking-[0.12em] text-muted";

export default function Footer() {
  const senderMountRef = useRef(null);

  // Sender polling-render lifecycle — LOCKED pattern salvaged from main's
  // Footer. The universal script (index.html) loads with ?explicit=true, so it
  // does NOT auto-render forms on scan; we render manually once the mount
  // exists, polling until the script has loaded (setTimeout, never a rAF).
  // StrictMode-safe (scar #7): the cancelled flag stops a pending poll; cleanup
  // destroys the rendered form AND clears the injected nodes so the second
  // dev-mount re-renders into a clean container. The form only ever renders
  // into the ONE [data-sender-form-id] mount below.
  useEffect(() => {
    let cancelled = false;
    let timer = null;
    const mount = senderMountRef.current;

    const tryRender = (attempt = 0) => {
      if (cancelled) return;
      if (window.senderForms && typeof window.senderForms.render === "function") {
        window.senderForms.render(LINKS.sender.formId);
      } else if (attempt < 50) {
        timer = setTimeout(() => tryRender(attempt + 1), 100);
      }
    };
    tryRender();

    return () => {
      cancelled = true;
      if (timer) clearTimeout(timer);
      if (window.senderForms && typeof window.senderForms.destroy === "function") {
        window.senderForms.destroy(LINKS.sender.formId);
      }
      if (mount) mount.replaceChildren();
    };
  }, []);

  return (
    <footer className="border-t border-line bg-surface-2 text-ink-dim">
      <div className="mx-auto max-w-[1280px] px-[clamp(1.25rem,4vw,3rem)] py-16">
        <div className="grid gap-12 md:grid-cols-2 lg:grid-cols-[1.4fr_1fr_1fr_1.4fr]">
          {/* Brand block */}
          <div>
            <Link to="/" data-cursor="magnet">
              <Wordmark className="text-lg" />
            </Link>
            <p className="mt-4 max-w-xs font-body text-sm leading-[1.7] text-ink-dim">
              {BRAND.name}. Agentic AI systems and AI-native products, drafted
              and built for how India actually works.
            </p>
          </div>

          {/* Navigation — same NAV source as the Navbar */}
          <nav aria-label="Footer">
            <h2 className={`${colLabel} border-b border-line pb-3`}>
              Navigation
            </h2>
            <ul className="mt-4 flex flex-col gap-2.5">
              {NAV.map((item, i) => (
                <li key={item.to}>
                  <Link
                    to={item.to}
                    className="font-body text-sm text-ink-dim transition-colors hover:text-ink"
                  >
                    <span className="mr-2 font-mono text-[0.6875rem] text-muted" aria-hidden="true">
                      {String(i + 1).padStart(2, "0")}
                    </span>
                    {item.label}
                  </Link>
                </li>
              ))}
            </ul>
          </nav>

          {/* Contact */}
          <div>
            <h2 className={`${colLabel} border-b border-line pb-3`}>Contact</h2>
            <ul className="mt-4 flex flex-col gap-2.5 font-body text-sm">
              <li>
                <a
                  href={`mailto:${LINKS.email}`}
                  className="text-ink-dim transition-colors hover:text-ink"
                >
                  {LINKS.email}
                </a>
              </li>
              <li>
                <a
                  href={LINKS.calendly}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-ink-dim transition-colors hover:text-ink"
                >
                  Book a call
                </a>
              </li>
              <li>
                <a
                  href={LINKS.linkedinCompany}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-ink-dim transition-colors hover:text-ink"
                >
                  LinkedIn
                </a>
              </li>
            </ul>
          </div>

          {/* #newsletter — the locked cross-route anchor + Sender mount. */}
          <section id="newsletter" aria-labelledby="newsletter-title">
            <h2
              id="newsletter-title"
              className={`${colLabel} border-b border-line pb-3`}
            >
              Updates
            </h2>
            <p className="mt-4 font-body text-sm text-ink-dim">
              Get updates. No spam. Just builds.
            </p>
            {/* Sender injects a CROSS-ORIGIN iframe whose theme (white card,
                old-brand orange) is dashboard-controlled — unstylable from CSS.
                The scoped invert() re-maps it into the direction's material
                language: white→graphite, black→bone, and the orange subhead
                (hue ~36°) lands at hue ~216° ≈ the blueprint-blue accent.
                Scoped utility on the mount only (scar #6); S14 finalizes the
                newsletter skin (ideally a dashboard re-theme, dropping this). */}
            <div
              ref={senderMountRef}
              className="sender-form-field mt-4 [filter:invert(0.94)]"
              data-sender-form-id={LINKS.sender.formId}
            />
          </section>
        </div>

        {/* Title-block bottom row */}
        <div className="mt-14 flex flex-wrap items-center justify-between gap-3 border-t border-line pt-6">
          <p className="font-mono text-[0.6875rem] uppercase tracking-[0.12em] text-muted">
            © {new Date().getFullYear()} {BRAND.name}. All rights reserved.
          </p>
          <p className="font-mono text-[0.6875rem] uppercase tracking-[0.12em] text-muted" aria-hidden="true">
            {BRAND.domain} · sheet 01 · rev 2026
          </p>
        </div>
      </div>
    </footer>
  );
}

